package com.odde.doughnut.controllers;

import com.odde.doughnut.controllers.dto.DueMemoryTrackers;
import com.odde.doughnut.entities.RecallPrompt;
import com.odde.doughnut.services.AuthorizationService;
import com.odde.doughnut.services.RecallService;
import com.odde.doughnut.testability.TestabilitySettings;
import com.odde.doughnut.utils.TimezoneUtils;
import java.sql.Timestamp;
import java.time.ZoneId;
import java.util.List;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.context.annotation.SessionScope;

@RestController
@SessionScope
@RequestMapping("/api/recalls")
class RecallsController {
  private final TestabilitySettings testabilitySettings;

  private final AuthorizationService authorizationService;
  private final RecallService recallService;

  @Autowired
  public RecallsController(
      TestabilitySettings testabilitySettings,
      AuthorizationService authorizationService,
      RecallService recallService) {
    this.testabilitySettings = testabilitySettings;
    this.authorizationService = authorizationService;
    this.recallService = recallService;
  }

  @GetMapping(value = {"/recalling"})
  @Transactional
  public DueMemoryTrackers recalling(
      @RequestParam(value = "timezone") String timezone,
      @RequestParam(value = "dueindays", required = false) Integer dueInDays) {
    authorizationService.assertLoggedIn();
    ZoneId timeZone = TimezoneUtils.parseTimezone(timezone);
    Timestamp currentUTCTimestamp = testabilitySettings.getCurrentUTCTimestamp();
    return recallService.getDueMemoryTrackers(
        authorizationService.getCurrentUser(),
        currentUTCTimestamp,
        timeZone,
        dueInDays == null ? 0 : dueInDays);
  }

  @GetMapping(value = {"/previously-answered"})
  @Transactional
  public List<RecallPrompt> previouslyAnswered(@RequestParam(value = "timezone") String timezone) {
    authorizationService.assertLoggedIn();
    ZoneId timeZone = TimezoneUtils.parseTimezone(timezone);
    Timestamp currentUTCTimestamp = testabilitySettings.getCurrentUTCTimestamp();
    return recallService.getPreviouslyAnsweredRecallPrompts(
        authorizationService.getCurrentUser(), currentUTCTimestamp, timeZone);
  }
}

package com.odde.doughnut.services;

import com.odde.doughnut.controllers.dto.DueMemoryTrackers;
import com.odde.doughnut.controllers.dto.MemoryTrackerLite;
import com.odde.doughnut.entities.MemoryTracker;
import com.odde.doughnut.entities.RecallPrompt;
import com.odde.doughnut.entities.User;
import com.odde.doughnut.entities.repositories.MemoryTrackerRepository;
import com.odde.doughnut.entities.repositories.RecallPromptRepository;
import com.odde.doughnut.utils.TimestampOperations;
import java.sql.Timestamp;
import java.time.ZoneId;
import java.util.List;
import java.util.stream.Stream;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class RecallService {

  private final UserService userService;
  private final MemoryTrackerRepository memoryTrackerRepository;
  private final RecallPromptRepository recallPromptRepository;

  @Autowired
  public RecallService(
      UserService userService,
      MemoryTrackerRepository memoryTrackerRepository,
      RecallPromptRepository recallPromptRepository) {
    this.userService = userService;
    this.memoryTrackerRepository = memoryTrackerRepository;
    this.recallPromptRepository = recallPromptRepository;
  }

  private int totalAssimilatedCount(User user) {
    return memoryTrackerRepository.countByUserNotRemoved(user.getId());
  }

  private Stream<MemoryTracker> getMemoryTrackersNeedToRepeat(
      User user, Timestamp currentUTCTimestamp, ZoneId timeZone, int dueInDays) {
    return userService.getMemoryTrackersNeedToRepeat(
        user,
        TimestampOperations.addHoursToTimestamp(currentUTCTimestamp, dueInDays * 24),
        timeZone);
  }

  public DueMemoryTrackers getDueMemoryTrackers(
      User user, Timestamp currentUTCTimestamp, ZoneId timeZone, int dueInDays) {
    List<MemoryTrackerLite> toRepeat =
        getMemoryTrackersNeedToRepeat(user, currentUTCTimestamp, timeZone, dueInDays)
            .map(
                mt -> {
                  MemoryTrackerLite lite = new MemoryTrackerLite();
                  lite.setMemoryTrackerId(mt.getId());
                  lite.setSpelling(mt.getSpelling() != null && mt.getSpelling());
                  return lite;
                })
            .toList();
    DueMemoryTrackers dueMemoryTrackers = new DueMemoryTrackers();
    dueMemoryTrackers.setDueInDays(dueInDays);
    dueMemoryTrackers.setToRepeat(toRepeat);

    // Set recall status
    dueMemoryTrackers.totalAssimilatedCount = totalAssimilatedCount(user);
    dueMemoryTrackers.setCurrentRecallWindowEndAt(
        TimestampOperations.alignByHalfADay(currentUTCTimestamp, timeZone));

    return dueMemoryTrackers;
  }

  public int getToRecallCount(User user, Timestamp currentUTCTimestamp, ZoneId timeZone) {
    return (int) getMemoryTrackersNeedToRepeat(user, currentUTCTimestamp, timeZone, 0).count();
  }

  public List<RecallPrompt> getPreviouslyAnsweredRecallPrompts(
      User user, Timestamp currentUTCTimestamp, ZoneId timeZone) {
    Timestamp startTime = TimestampOperations.startOfHalfADay(currentUTCTimestamp, timeZone);
    Timestamp endTime = TimestampOperations.alignByHalfADay(currentUTCTimestamp, timeZone);

    return recallPromptRepository.findAnsweredRecallPromptsInTimeRange(
        user.getId(), startTime, endTime);
  }
}

package com.odde.doughnut.entities.repositories;

import com.odde.doughnut.entities.MemoryTracker;
import java.sql.Timestamp;
import java.util.List;
import java.util.stream.Stream;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.CrudRepository;
import org.springframework.data.repository.query.Param;

public interface MemoryTrackerRepository extends CrudRepository<MemoryTracker, Integer> {
  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.assimilated_at > :since "
              + "   AND rp.removed_from_tracking IS FALSE "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  List<MemoryTracker> findAllByUserAndAssimilatedAtGreaterThan(
      @Param("userId") Integer userId, @Param("since") Timestamp since);

  @Query(value = "SELECT count(*) " + byUserIdFrom, nativeQuery = true)
  int countByUserNotRemoved(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT rp.* "
              + byUserIdFrom
              + " AND rp.next_recall_at <= :nextRecallAt ORDER BY rp.next_recall_at, IFNULL(rp.spelling, 0) DESC",
      nativeQuery = true)
  Stream<MemoryTracker> findAllByUserAndNextRecallAtLessThanEqualOrderByNextRecallAt(
      @Param("userId") Integer userId, @Param("nextRecallAt") Timestamp nextRecallAt);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL "
              + "   AND rp.note_id = :noteId",
      nativeQuery = true)
  List<MemoryTracker> findByUserAndNote(Integer userId, @Param("noteId") Integer noteId);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + byUserIdWhere
              + " ORDER BY rp.assimilated_at DESC LIMIT 100",
      nativeQuery = true)
  List<MemoryTracker> findLast100ByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT rp.* FROM memory_tracker rp "
              + byUserIdWhere
              + " AND rp.last_recalled_at IS NOT NULL "
              + " ORDER BY rp.last_recalled_at DESC LIMIT 500",
      nativeQuery = true)
  List<MemoryTracker> findLast100RecalledByUser(@Param("userId") Integer userId);

  List<MemoryTracker> findByNote_IdIn(List<Integer> noteIds);

  String byUserIdFrom =
      " FROM memory_tracker rp "
          + " WHERE rp.user_id = :userId "
          + "   AND rp.removed_from_tracking IS FALSE "
          + "   AND rp.deleted_at IS NULL ";

  String byUserIdWhere =
      " WHERE rp.user_id = :userId "
          + "   AND rp.removed_from_tracking IS FALSE "
          + "   AND rp.deleted_at IS NULL ";

  @Query(
      value =
          "SELECT MAX(rp.assimilated_at) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  Timestamp findLastAssimilationTimeByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT MAX(rp.last_recalled_at) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  Timestamp findLastRecallTimeByUser(@Param("userId") Integer userId);

  @Query(
      value =
          "SELECT COUNT(*) FROM memory_tracker rp "
              + " WHERE rp.user_id = :userId "
              + "   AND rp.deleted_at IS NULL",
      nativeQuery = true)
  long countByUser(@Param("userId") Integer userId);
}

package com.odde.doughnut.services;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.equalTo;
import static org.hamcrest.Matchers.is;
import static org.hamcrest.Matchers.nullValue;

import com.odde.doughnut.entities.MemoryTracker;
import com.odde.doughnut.entities.Note;
import com.odde.doughnut.entities.User;
import com.odde.doughnut.testability.MakeMe;
import com.odde.doughnut.utils.TimestampOperations;
import java.sql.Timestamp;
import java.time.ZoneId;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

@SpringBootTest
@ActiveProfiles("test")
@Transactional
public class RecallServiceWithSpacedRepetitionAlgorithmTest {
  @Autowired MakeMe makeMe;
  @Autowired UserService userService;
  User user;
  User anotherUser;

  @BeforeEach
  void setup() {
    user = makeMe.aUser().withSpaceIntervals("1, 2, 4, 8").please();
    anotherUser = makeMe.aUser().please();
  }

  @Nested
  class WhenThereIsOneNote {
    Note note;

    @BeforeEach
    void setup() {
      note = makeMe.aNote().notebookOwnedBy(user).please();
    }

    @Test
    void whenThereIsNoRecalledNotesForUser() {
      MemoryTracker memoryTracker = makeMe.aMemoryTrackerFor(note).by(anotherUser).please();
      assertThat(getOneMemoryTrackerNeedToRepeat(daysAfterBase(memoryTracker, 1)), is(nullValue()));
    }

    @ParameterizedTest
    @CsvSource({
      "1,   0, false",
      "1,   1, true",
      "1,   2, true",
      "1,  10, true",
      "2,   0, false",
      "2,   1, false",
      "2,   2, true",
      "2,  10, true",
      "3,   0, false",
      "3,   1, false",
      "3,   3, false",
      "3,   4, true",
    })
    void whenThereIsOneRecalledNotesForUser(
        Integer recallDone, Integer recallDay, Boolean expectedToRepeat) {
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(user).afterNthStrictRecall(recallDone).please();
      MemoryTracker mostUrgentMemoryTracker =
          getOneMemoryTrackerNeedToRepeat(daysAfterBase(memoryTracker, recallDay));
      assertThat(mostUrgentMemoryTracker != null, is(expectedToRepeat));
    }

    @Nested
    class RecallTimeIsAlignedByHalfADay {
      @ParameterizedTest
      @CsvSource({
        "9,  6,    true",
        "16, 0,    false",
        "16, 15,   true",
        "16, 17,   true",
      })
      void atHourInTheNextDay(
          Integer lastRepeatHour, Integer currentHour, Boolean expectedToRepeat) {
        MemoryTracker memoryTracker = makeMe.aMemoryTrackerFor(note).by(user).please();
        memoryTracker.setNextRecallAt(
            makeMe.aTimestamp().of(2, lastRepeatHour).fromShanghai().please());
        final Timestamp timestamp = makeMe.aTimestamp().of(2, currentHour).fromShanghai().please();
        MemoryTracker mostUrgentMemoryTracker = getOneMemoryTrackerNeedToRepeat(timestamp);
        assertThat(mostUrgentMemoryTracker != null, is(expectedToRepeat));
      }
    }

    @Nested
    class EarlyAndLateRecall {
      @ParameterizedTest
      @CsvSource({
        "0, 0,  100.0",
        "0, 1,  110.0",
        "2, -1,  115.0",
        "2, 0, 120.0",
        "2, 1, 115.0",
        "2, 100, 100.0",
      })
      void aMemoryTrackerHasBeenRecalledStrictly(
          int ntimes, Integer daysDelay, float expectedForgettingCurveIndex) {
        MemoryTracker memoryTracker =
            makeMe.aMemoryTrackerFor(note).by(user).afterNthStrictRecall(ntimes).please();
        Timestamp currentUTCTimestamp =
            TimestampOperations.addHoursToTimestamp(
                memoryTracker.getNextRecallAt(), daysDelay * 24);
        memoryTracker.markAsRecalled(currentUTCTimestamp, true, null);
        assertThat(memoryTracker.getForgettingCurveIndex(), equalTo(expectedForgettingCurveIndex));
      }
    }
  }

  private MemoryTracker getOneMemoryTrackerNeedToRepeat(Timestamp timestamp) {
    return userService
        .getMemoryTrackersNeedToRepeat(user, timestamp, ZoneId.of("Asia/Shanghai"))
        .findFirst()
        .orElse(null);
  }

  private Timestamp daysAfterBase(MemoryTracker memoryTracker, Integer recallDay) {
    return TimestampOperations.addHoursToTimestamp(
        memoryTracker.getLastRecalledAt(), recallDay * 24);
  }
}

package com.odde.doughnut.controllers;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.hasSize;
import static org.junit.jupiter.api.Assertions.*;

import com.odde.doughnut.controllers.dto.DueMemoryTrackers;
import com.odde.doughnut.controllers.dto.NoteDeleteReferenceHandling;
import com.odde.doughnut.entities.MemoryTracker;
import com.odde.doughnut.entities.Note;
import com.odde.doughnut.entities.RecallPrompt;
import com.odde.doughnut.services.NoteService;
import com.odde.doughnut.utils.TimestampOperations;
import java.sql.Timestamp;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.server.ResponseStatusException;

class RecallsControllerTests extends ControllerTestBase {
  @Autowired RecallsController controller;
  @Autowired NoteService noteService;

  @BeforeEach
  void setup() {
    currentUser.setUser(makeMe.aUser().please());
  }

  RecallsController nullUserController() {
    currentUser.setUser(null);
    return controller;
  }

  @Nested
  class Repeat {
    @Test
    void shouldNotBeAbleToSeeNoteIDontHaveAccessTo() {
      assertThrows(
          ResponseStatusException.class,
          () -> nullUserController().recalling("Asia/Shanghai", null));
    }

    @ParameterizedTest
    @CsvSource(
        useHeadersInDisplayName = true,
        delimiter = '|',
        textBlock =
            """
                next recall at (in hours) | timezone     | expected count
                #------------------------------------------------------------
                -1                        | Asia/Tokyo   | 1
                0                         | Asia/Tokyo   | 1
                4                         | Asia/Tokyo   | 0
                4                         | Europe/Paris | 1
                12                        | Europe/Paris | 0
                """)
    void shouldGetMemoryTrackersBasedOnTimezone(
        int nextRecallAtHours, String timezone, int expectedCount) {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe
          .aMemoryTrackerBy(currentUser.getUser())
          .nextRecallAt(TimestampOperations.addHoursToTimestamp(currentTime, nextRecallAtHours))
          .please();
      DueMemoryTrackers dueMemoryTrackers = controller.recalling(timezone, null);
      assertThat(dueMemoryTrackers.getToRepeat(), hasSize(expectedCount));
    }

    @Test
    void shouldIncludeRecallStatusInDueMemoryTrackers() {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe.aMemoryTrackerBy(currentUser.getUser()).nextRecallAt(currentTime).please();

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      assertEquals(1, dueMemoryTrackers.getToRepeat().size());
      assertEquals(1, dueMemoryTrackers.totalAssimilatedCount);
      // currentTime is 1989-01-01 00:00:00 UTC, which is 1989-01-01 08:00:00 in Asia/Shanghai
      // Since hour < 12, alignByHalfADay returns same day at 12:00:00 Asia/Shanghai = 04:00:00 UTC
      Timestamp expectedEndAt = TimestampOperations.addHoursToTimestamp(currentTime, 4);
      assertEquals(expectedEndAt, dueMemoryTrackers.getCurrentRecallWindowEndAt());
    }

    @ParameterizedTest
    @CsvSource({
      "0,  12", "6,  6", "11, 1", "12, 12", "18, 6",
    })
    void shouldSetCurrentRecallWindowEndAtAlignedByHalfADay(
        int currentHour, int expectedHoursToAdd) {
      Timestamp currentTime = makeMe.aTimestamp().of(1, currentHour).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);
      makeMe.aMemoryTrackerBy(currentUser.getUser()).nextRecallAt(currentTime).please();

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      Timestamp expectedEndAt =
          TimestampOperations.addHoursToTimestamp(currentTime, expectedHoursToAdd);
      assertEquals(expectedEndAt, dueMemoryTrackers.getCurrentRecallWindowEndAt());
      // Verify it's not affected by dueInDays
      DueMemoryTrackers dueMemoryTrackersWithDays = controller.recalling("Asia/Shanghai", 3);
      assertEquals(expectedEndAt, dueMemoryTrackersWithDays.getCurrentRecallWindowEndAt());
    }

    @Test
    void shouldExcludeMemoryTrackersForDeletedNotesFromRecallLists() {
      Timestamp currentTime = makeMe.aTimestamp().of(0, 0).please();
      testabilitySettings.timeTravelTo(currentTime);
      Note activeNote = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      Note deletedNote = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      makeMe
          .aMemoryTrackerFor(activeNote)
          .by(currentUser.getUser())
          .nextRecallAt(currentTime)
          .please();
      makeMe
          .aMemoryTrackerFor(deletedNote)
          .by(currentUser.getUser())
          .nextRecallAt(currentTime)
          .please();

      noteService.destroy(
          deletedNote, NoteDeleteReferenceHandling.LEAVE_DEAD_LINKS, currentUser.getUser());

      DueMemoryTrackers dueMemoryTrackers = controller.recalling("Asia/Shanghai", 0);

      assertEquals(1, dueMemoryTrackers.getToRepeat().size());
      assertEquals(1, dueMemoryTrackers.totalAssimilatedCount);
      assertThat(dueMemoryTrackers.getToRepeat(), hasSize(1));
    }
  }

  @Nested
  class PreviouslyAnswered {
    @Test
    void shouldNotBeAbleToAccessWithoutLogin() {
      assertThrows(
          ResponseStatusException.class,
          () -> nullUserController().previouslyAnswered("Asia/Shanghai"));
    }

    @Test
    void shouldReturnEmptyListWhenNoAnsweredRecallPrompts() {
      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");
      assertThat(results, hasSize(0));
    }

    @Test
    void shouldReturnAnsweredRecallPromptsInCurrentWindow() {
      // Set current time to 10:00 AM Shanghai time (window: 0:00-12:00)
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      // Create an answered recall prompt with answer timestamp within current window
      makeMe
          .aRecallPrompt()
          .withPredefinedQuestionForNote(note)
          .forMemoryTracker(memoryTracker)
          .answerChoiceIndex(0)
          .answerTimestamp(currentTime)
          .please();

      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");

      assertThat(results, hasSize(1));
      assertEquals(com.odde.doughnut.entities.QuestionType.MCQ, results.get(0).getQuestionType());
    }

    @Test
    void shouldNotReturnAnsweredRecallPromptsFromPreviousWindow() {
      // Answer a question in a previous window (yesterday at 10:00 AM)
      Timestamp previousWindowTime = makeMe.aTimestamp().of(0, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(previousWindowTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      makeMe
          .aRecallPrompt()
          .withPredefinedQuestionForNote(note)
          .forMemoryTracker(memoryTracker)
          .answerChoiceIndex(0)
          .answerTimestamp(previousWindowTime)
          .please();

      // Move to current window (next day at 10:00 AM)
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      List<RecallPrompt> results = controller.previouslyAnswered("Asia/Shanghai");

      assertThat(results, hasSize(0));
    }

    @Test
    void shouldReturnSpellingResultsInCurrentWindow() {
      Timestamp currentTime = makeMe.aTimestamp().of(1, 2).fromShanghai().please();
      testabilitySettings.timeTravelTo(currentTime);

      Note note = makeMe.aNote().notebookOwnedBy(currentUser.getUser()).please();
      MemoryTracker memoryTracker =
          makeMe.aMemoryTrackerFor(note).by(currentUser.getUser()).please();

      // Create an answered spelling recall prompt
      makeMe
          .aRecallPrompt()
          .forMemoryTracker(memoryTracker)
          .spelling()
          .answerSpelling("test answer")
          .answerTimestamp(currentTime)
          .please();

