package com.odde.doughnut.factoryServices;

import com.odde.doughnut.entities.EntityIdentifiedByIdOnly;
import jakarta.persistence.EntityManager;
import jakarta.persistence.TypedQuery;
import org.springframework.stereotype.Service;

@Service
public class EntityPersister {
  private final EntityManager entityManager;

  public EntityPersister(EntityManager entityManager) {
    this.entityManager = entityManager;
  }

  public <T> T save(T entity) {
    if (entity instanceof EntityIdentifiedByIdOnly instance) {
      if (instance.getId() != null) {
        return entityManager.merge(entity);
      }
    }
    entityManager.persist(entity);
    return entity;
  }

  public <T extends EntityIdentifiedByIdOnly> T merge(T entity) {
    return entityManager.merge(entity);
  }

  public <T extends EntityIdentifiedByIdOnly> T remove(T entity) {
    T merged = entityManager.merge(entity);
    entityManager.remove(merged);
    entityManager.flush();
    return merged;
  }

  public <T> T find(Class<T> entityClass, Object primaryKey) {
    return entityManager.find(entityClass, primaryKey);
  }

  public void flush() {
    entityManager.flush();
  }

  public void flushAndClear() {
    entityManager.flush();
    entityManager.clear();
  }

  public void refresh(Object entity) {
    entityManager.refresh(entity);
  }

  public <T> TypedQuery<T> createQuery(String qlString, Class<T> resultClass) {
    return entityManager.createQuery(qlString, resultClass);
  }
}

package com.odde.doughnut.testability.builders;

import java.sql.Timestamp;
import java.time.ZoneId;
import java.time.ZonedDateTime;

public class TimestampBuilder {
  private int day;
  private int hour;
  ZoneId userTimeZone = ZoneId.of("UTC");

  public TimestampBuilder of(int day, int hour) {
    this.day = day;
    this.hour = hour;
    return this;
  }

  public TimestampBuilder fromShanghai() {
    userTimeZone = ZoneId.of("Asia/Shanghai");
    return this;
  }

  public Timestamp please() {
    ZonedDateTime userDateTime = ZonedDateTime.of(1989, 1, 1, hour, 0, 0, 0, userTimeZone);
    ZonedDateTime utc = userDateTime.withZoneSameInstant(ZoneId.systemDefault());

    return Timestamp.valueOf(utc.plusDays(day).toLocalDateTime());
  }
}

